export default function FloatingActionMenu() {
  const [open, setOpen] = useState(false);
  const actions = [
    { icon: "✏️", label: "Edit" },
    { icon: "📎", label: "Attach" },
    { icon: "📤", label: "Share" },
  ];

  return (
