        <button
          onClick={() => setOpen(!open)}
          className={`w-14 h-14 rounded-full bg-blue-600 text-white shadow-xl flex items-center justify-center text-2xl transition-transform duration-300 hover:bg-blue-700 ${
            open ? "rotate-45" : ""
